export function IntegrationsSection() {
  return (
    <div className="container mx-auto mb-32 grid grid-cols-1 gap-12 p-4 md:grid-cols-2 md:items-center">
      <div className="max-w-xl space-y-5">
        <h2 className="font-display text-4xl tracking-tight text-foreground sm:text-5xl md:text-6xl">
          {m.home_page__integrations__heading()}
        </h2>
        <p className="text-lg leading-8 text-muted-foreground">
          {m.home_page__integrations__description()}
        </p>
      </div>

      <div className="place-items-end">
        <div className="relative size-90 mask-[radial-gradient(ellipse_at_center,black,black,transparent)]">
          {tiles.map((tile) => (
            <IntegrationCard key={`${tile.row}_${tile.col}`} {...tile} />
          ))}
        </div>
      </div>
    </div>
  );
}

function IntegrationCard({ row, col, logo }: TileData) {
  return (
    <div
      className={cn(
        "absolute flex size-18 items-center justify-center rounded-md border",
        logo ? "bg-card shadow-xs dark:bg-card/60" : "bg-secondary/30 dark:bg-background", // Styling for empty tiles
      )}
      style={{
        left: col * 72, // 72px cell
        top: row * 72,
      }}
    >
      {logo && (
        <div
          className={cn(
            "pointer-events-none size-8 select-none [&>svg]:size-full [&>svg]:object-contain",
            logo.isInvertable && "dark:invert",
          )}
          role="img"
          aria-label={logo.alt}
        >
          {logo.svg}
        </div>
      )}
    </div>
  );
}
